mapper.update:
UPDATE employee_shifts
SET shift_type = #{shiftType},
    on_duty = #{onDuty},
    remark = #{remark}
WHERE employee_id = #{employeeId}
  AND shift_date = #{shiftDate}

mapper.delete:
DELETE FROM employee_shifts
WHERE employee_id = #{employeeId}
  AND shift_id = #{shiftId}
  AND shift_date = #{shiftDate}

mapper.select:
SELECT s.id AS shift_id, s.shift_name, s.start_time, s.end_time, es.shift_date
FROM shifts s
         JOIN employee_shifts es ON s.id = es.shift_id
WHERE es.employee_id = #{employeeId}
  AND es.shift_date BETWEEN #{startDate} AND #{endDate}
ORDER BY es.shift_date, s.start_time

SELECT COUNT(DISTINCT employee_id)
FROM employee_shifts
WHERE shift_date = CURRENT_DATE;
